html:
{% set practitioner = frappe.get_doc("Healthcare Practitioner", doc.practitioner) if doc.practitioner else None %}
{% set patient = frappe.get_doc("Patient", doc.patient) if doc.patient else None %}

<style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;700&display=swap');

    .prescription-container {
        font-family: 'Inter', Arial, sans-serif;
        padding: 40px;
        color: #333;
        position: relative;
        min-height: 1000px;
        background-color: white;
    }

    .header {
        display: flex;
        justify-content: space-between;
        align-items: flex-start;
        margin-bottom: 20px;
    }

    .logo-section {
        display: flex;
        flex-direction: column;
    }

    .logo-container {
        display: flex;
        align-items: center;
        gap: 10px;
        margin-bottom: 5px;
    }

    .s2w-icon {
        width: 40px;
        height: 40px;
        border-radius: 50%;
        background-color: #8BC34A;
        color: white;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: bold;
        font-size: 18px;
    }

    .logo-text {
        font-size: 24px;
        font-weight: 700;
        letter-spacing: -1px;
    }

    .wellness-banner {
        background-color: #8BC34A;
        color: white;
        padding: 4px 12px;
        font-size: 10px;
        font-weight: 700;
        text-transform: uppercase;
        width: fit-content;
    }

    .practitioner-info {
        text-align: right;
    }

    .practitioner-info h1 {
        margin: 0;
        font-size: 18px;
        font-weight: 700;
    }

    .practitioner-info p {
        margin: 2px 0;
        font-size: 12px;
    }

    .divider {
        border-top: 1px solid #000;
        margin: 15px 0;
        width: 100%;
    }

    .address-section {
        display: flex;
        justify-content: space-between;
        font-size: 11px;
        margin-bottom: 15px;
    }

    .patient-date-row {
        display: flex;
        justify-content: space-between;
        padding: 8px 0;
        font-size: 14px;
        border-top: 1px solid #000;
        border-bottom: 1px solid #000;
        margin-bottom: 20px;
    }

    .prescription-body {
        position: relative;
        min-height: 400px;
        padding: 20px 0;
        background-image: radial-gradient(#8BC34A33 1px, transparent 1px);
        background-size: 20px 20px;
    }

    .medication-table {
        width: 100%;
        border-collapse: collapse;
    }

    .medication-table td {
        padding: 12px 0;
        vertical-align: top;
        font-size: 13px;
    }

    .medication-name {
        font-weight: 700;
        font-size: 14px;
    }

    .footer {
        position: absolute;
        bottom: 40px;
        left: 40px;
        right: 40px;
        display: flex;
        justify-content: space-between;
        align-items: flex-end;
    }

    .signature-area {
        width: 250px;
    }

    .signature-img {
        max-width: 150px;
        margin-bottom: 5px;
    }

    .signature-line {
        border-top: 1px solid #000;
        margin-bottom: 5px;
    }

    .contact-details {
        text-align: right;
        font-size: 12px;
    }

    .contact-item {
        display: flex;
        align-items: center;
        justify-content: flex-end;
        gap: 8px;
        margin-bottom: 5px;
    }

    .icon-circle {
        width: 18px;
        height: 18px;
        border-radius: 50%;
        background-color: #000;
        color: white;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 10px;
    }

    .bottom-accent {
        position: absolute;
        bottom: 0;
        right: 0;
        width: 100px;
        height: 8px;
        background-color: #8BC34A;
    }
</style>

<div class="prescription-container">
    <div class="header">
        <div class="logo-section">
            <div class="logo-container">
                <div class="s2w-icon">S2W</div>
                <div class="logo-text">slim 2 well</div>
            </div>
            <div class="wellness-banner">WELLNESS SIMPLIFIED</div>
        </div>
        <div class="practitioner-info">
            <h1>Prescription/Voorskrif</h1>
            <p><strong>Dr. {{ practitioner.practitioner_name if practitioner else 'A Terblanche' }}</strong></p>
            <p>{{ practitioner.qualification or 'M.B Ch.B (Pret)' }}</p>
            <p><strong>PR: {{ practitioner.practice_number or '1579657' }}</strong></p>
            <p>SAMDC {{ practitioner.hpcsa_registration_number or 'MP0407968' }}</p>
        </div>
    </div>

    <div class="divider"></div>

    <div class="address-section">
        <div class="physical-address">
            {% if practitioner and practitioner.practice_address %}
                {{ practitioner.practice_address.replace('\n', '<br>') }}
            {% else %}
                Bospoort 1479(7)<br>
                Warmbad X24<br>
                BELA BELA
            {% endif %}
        </div>
        <div class="postal-address" style="text-align: right;">
            {% set postal = practitioner.practitioner_postal_address if practitioner else None %}
            {% if postal %}
                {{ postal.replace('\n', '<br>') }}
            {% else %}
                Postnet Suite 202<br>
                Privaatsak X1604<br>
                BELA BELA, 0480
            {% endif %}
        </div>
    </div>

    <div class="patient-date-row">
        <div><strong>Patient Name:</strong> {{ doc.patient_name or '____________________' }}</div>
        <div><strong>Date:</strong> {{ frappe.utils.formatdate(doc.encounter_date or frappe.utils.today()) }}</div>
    </div>

    <div class="prescription-body">
        <table class="medication-table">
            <tbody>
                {% if doc.drug_prescription %}
                    {% for med in doc.drug_prescription %}
                        <tr>
                            <td>
                                <div class="medication-name">{{ med.drug_name or med.medication }}</div>
                                <div style="font-size: 11px; margin-top: 4px;">
                                    {{ med.dosage }}
                                    {% if med.period %}
                                         - {{ med.period }}
                                    {% endif %}
                                </div>
                                {% if med.comment %}
                                    <div style="font-style: italic; color: #666; font-size: 11px;">{{ med.comment }}</div>
                                {% endif %}
                            </td>
                        </tr>
                    {% endfor %}
                {% else %}
                    <tr>
                        <td style="color: #ccc; text-align: center; padding-top: 100px;">
                            No medications prescribed.
                        </td>
                    </tr>
                {% endif %}
            </tbody>
        </table>
    </div>

    <div class="footer">
        <div class="signature-area">
            <div style="height: 40px;"></div>
            <div class="signature-line"></div>
            <div style="font-size: 12px; font-weight: 700;">
                Dr. {{ practitioner.practitioner_name if practitioner else 'A Terblanche' }} | {{ practitioner.qualification or 'M.B Ch.B (Pret)' }}
            </div>
        </div>

        <div class="contact-details">
            <div class="contact-item">
                082 784 4343
                <div class="icon-circle">📞</div>
            </div>
            <div class="contact-item">
                docinafrica@mweb.co.za
                <div class="icon-circle">✉️</div>
            </div>
        </div>
    </div>

    <div class="bottom-accent"></div>
</div>
